import React, { useEffect } from 'react'
import useTreeStore from './useTreeStore'
import useTreeData from './useTreeData'
import Tree from './Tree'

function FileFolderContainer() {
    const { data, loading, error } = useTreeData()
    const treeData = useTreeStore((state) => state.treeData)
    const setTreeData = useTreeStore((state) => state.setTreeData)
    useEffect(() => {
        if (data) {
            setTreeData(data)
        }
    }, [data])

    const setSearchQuery = useTreeStore((state) => state.setSearchQuery)
    const searchQuery = useTreeStore((state) => state.searchQuery)

    if (treeData.length > 0) {
        return (
            <>
                <input
                    type="text"
                    placeholder="Search files and folders..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    style={{ marginBottom: '8px', padding: '4px 8px', width: '100%', boxSizing: 'border-box' }}
                />
                <Tree treeData={treeData} />
            </>
        )
    }
}
export default FileFolderContainer
